TriggerOraclev10g.body:
DECLARE 
envbq_status number;
valor_envbq_update number;
vro_error  tkr_errores%ROWTYPE;
BEGIN
    -- En el caso de INSERT
    IF INSERTING THEN

       SELECT (SELECT ENVIO_BQ FROM TKRBQ_DIFICULTADES WHERE ID = :NEW.ID AND ENVIO_BQ != 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NOT NULL THEN
        DELETE TKRBQ_DIFICULTADES WHERE ID = :NEW.ID AND ENVIO_BQ != 1;
       END IF;        

        INSERT INTO TKRBQ_DIFICULTADES (
            ENVIO_BQ,
            ID,
            DIFICULTAD,
            FECHA_CREACION
        )
        VALUES (
            0, -- ENVIO_BQ por defecto
            :NEW.ID,
            :NEW.DIFICULTAD,
            :NEW.FECHA_CREACION
        );
    END IF;

    -- En el caso de UPDATE
    IF UPDATING THEN
        SELECT (SELECT ENVIO_BQ FROM TKRBQ_DIFICULTADES WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NULL THEN

            INSERT INTO TKRBQ_DIFICULTADES (
                ENVIO_BQ,
                ID,
                DIFICULTAD,
                FECHA_CREACION
            )
            VALUES (
                2, -- ENVIO_BQ por defecto
                :NEW.ID,
                :NEW.DIFICULTAD,
                :NEW.FECHA_CREACION
            );

       ELSE
            IF envbq_status = 0 THEN 
                valor_envbq_update := 0;
            ELSE
                valor_envbq_update := 2;
            END IF;

            UPDATE TKRBQ_DIFICULTADES
            SET
                ENVIO_BQ = valor_envbq_update,
                ID = :NEW.ID,
                DIFICULTAD = :NEW.DIFICULTAD,
                FECHA_CREACION = :NEW.FECHA_CREACION
            WHERE ID = :OLD.ID AND ENVIO_BQ != 1;
        END IF;
    END IF;

        -- Caso DELETE
    IF DELETING THEN

       SELECT (SELECT ENVIO_BQ FROM TKRBQ_DIFICULTADES WHERE ID = :OLD.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NOT NULL THEN
        DELETE TKRBQ_DIFICULTADES WHERE ID = :OLD.ID AND ENVIO_BQ != 1;
       END IF;        

        INSERT INTO TKRBQ_DIFICULTADES (
            ENVIO_BQ,
            ID,
            DIFICULTAD,
            FECHA_CREACION
        )
        VALUES (
            -1, -- ENVIO_BQ para DELETE
            :OLD.ID,
            :OLD.DIFICULTAD,
            :OLD.FECHA_CREACION
        );
    END IF;

    EXCEPTION
        WHEN OTHERS
        THEN
            vro_error.nombre_programa := 'TRG_SYNC_TKR_DIFICULTADES';
            vro_error.nombre_metodo := 'TRIGGER_SYNC_BQ';
            vro_error.parametros := 'id de consultas: '||:old.id;
            uti_ge_excepciones_pkg.p_grabar_log (vro_error);

END;
